-- Employee master import (MMDI Location Wise Emp Details-17-7-26.xls, Master
-- sheet, 498 rows -- location-specific sheets are subsets of the same data
-- and are not re-imported separately to avoid duplicates).
-- Idempotent, re-runnable via ON CONFLICT (employee_code).
-- status/status_label are set to a flat 'Active' for all rows since the
-- source file has no termination/leave-status column -- update manually or
-- extend the import if that distinction matters.

on conflict (employee_code) do update set
  name = excluded.name,
  role = excluded.role,
  department = excluded.department,
  location = excluded.location,
  off_email = excluded.off_email,
  off_phone = excluded.off_phone,
  personal_email = excluded.personal_email,
  personal_phone = excluded.personal_phone,
  date_of_joining = excluded.date_of_joining,
  date_of_birth = excluded.date_of_birth,
  gender = excluded.gender;
